import os
import datetime
import functools

from flask import Flask, request, jsonify, g
import jwt
from werkzeug.security import generate_password_hash, check_password_hash

app = Flask(__name__)

# Configuration
app.config["SECRET_KEY"] = os.environ.get("JWT_SECRET_KEY", "change-this-to-a-strong-random-secret")
app.config["JWT_ALGORITHM"] = "HS256"
app.config["JWT_EXPIRATION_MINUTES"] = 30
app.config["JWT_ISSUER"] = "flask-jwt-auth"

# ---------------------------------------------------------------------------
# In-memory user store (replace with a real database in production)
# ---------------------------------------------------------------------------
USERS: dict[str, dict] = {}


def _create_token(user_id: str, username: str) -> str:
    """Create a signed JWT with required claims."""
    now = datetime.datetime.now(datetime.timezone.utc)
    payload = {
        "sub": user_id,
        "username": username,
        "iat": now,
        "exp": now + datetime.timedelta(minutes=app.config["JWT_EXPIRATION_MINUTES"]),
        "iss": app.config["JWT_ISSUER"],
    }
    token = jwt.encode(payload, app.config["SECRET_KEY"], algorithm=app.config["JWT_ALGORITHM"])
    return token


def _decode_token(token: str) -> dict:
    """Decode and verify a JWT with explicit algorithm allowlisting and claim requirements."""
    payload = jwt.decode(
        token,
        app.config["SECRET_KEY"],
        algorithms=[app.config["JWT_ALGORITHM"]],  # explicit allowlist
        options={
            "require": ["exp", "iat", "sub", "iss"],  # all must be present
        },
        issuer=app.config["JWT_ISSUER"],  # verify issuer claim
    )
    return payload


# ---------------------------------------------------------------------------
# Decorator for protecting routes
# ---------------------------------------------------------------------------
def jwt_required(f):
    """Decorator that ensures a valid JWT is present in the Authorization header."""

    @functools.wraps(f)
    def decorated(*args, **kwargs):
        auth_header = request.headers.get("Authorization", "")
        if not auth_header.startswith("Bearer "):
            return jsonify({"error": "Missing or malformed Authorization header"}), 401

        token = auth_header.split(" ", 1)[1]

        try:
            payload = _decode_token(token)
        except jwt.ExpiredSignatureError:
            return jsonify({"error": "Token has expired"}), 401
        except jwt.InvalidIssuerError:
            return jsonify({"error": "Invalid token issuer"}), 401
        except jwt.MissingRequiredClaimError as exc:
            return jsonify({"error": f"Token missing required claim: {exc}"}), 401
        except jwt.InvalidTokenError as exc:
            return jsonify({"error": f"Invalid token: {exc}"}), 401

        # Make the authenticated user available via Flask's `g`
        g.current_user = {
            "user_id": payload["sub"],
            "username": payload["username"],
        }
        return f(*args, **kwargs)

    return decorated


# ---------------------------------------------------------------------------
# Public routes
# ---------------------------------------------------------------------------
@app.route("/register", methods=["POST"])
def register():
    """Register a new user.

    Expects JSON: {"username": "...", "password": "..."}
    """
    data = request.get_json(silent=True) or {}
    username = data.get("username", "").strip()
    password = data.get("password", "")

    if not username or not password:
        return jsonify({"error": "username and password are required"}), 400

    if username in USERS:
        return jsonify({"error": "User already exists"}), 409

    user_id = str(len(USERS) + 1)
    USERS[username] = {
        "user_id": user_id,
        "username": username,
        "password_hash": generate_password_hash(password),
    }

    return jsonify({"message": "User registered successfully", "user_id": user_id}), 201


@app.route("/login", methods=["POST"])
def login():
    """Authenticate and return a JWT.

    Expects JSON: {"username": "...", "password": "..."}
    """
    data = request.get_json(silent=True) or {}
    username = data.get("username", "").strip()
    password = data.get("password", "")

    user = USERS.get(username)
    if user is None or not check_password_hash(user["password_hash"], password):
        return jsonify({"error": "Invalid username or password"}), 401

    token = _create_token(user["user_id"], user["username"])
    return jsonify({
        "access_token": token,
        "token_type": "Bearer",
        "expires_in_minutes": app.config["JWT_EXPIRATION_MINUTES"],
    })


